inline:<div id="header-root" class="c1-container">
  <style>
    #header-root { font-family: 'Montserrat', sans-serif; background: #0A0A12; color: #00F2FF; padding: 64px 16px; text-align: center; overflow: hidden; position: relative; }
    .c1-branding { font-size: 1.2rem; letter-spacing: 0.3em; text-transform: uppercase; color: #FF00E5; margin-bottom: 16px; }
    .c1-title { font-size: 4rem; font-weight: 800; line-height: 1.1; margin-bottom: 24px; tracking: -0.02em; }
    .c1-dna-anchor { position: relative; width: 200px; height: 200px; margin: 0 auto; }
    .c1-helix { position: absolute; width: 100%; height: 100%; border: 2px solid #00F2FF; border-radius: 50%; animation: rotate 10s linear infinite; }
    .c1-helix::after { content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 100%; border: 2px solid #FF00E5; border-radius: 50%; transform: rotateX(90deg); }
    @keyframes rotate { from { transform: rotate(0deg); } to { transform: rotate(360deg); } }
    @media (prefers-reduced-motion: reduce) { .c1-helix { animation: none !important; }
  }
  </style>
  <div class="c1-branding">Genomic Arts 2026</div>
  <h1 class="c1-title">The Architecture <br>of Life</h1>
  <div class="c1-dna-anchor" id="header-root-visual">
    <div class="c1-helix"></div>
  </div>
  <script>
    window.c1_mount = () => {};
    window.c1_destroy = () => {};
    window.c1_initializeHeaderAnimation = () => {
      if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
      document.getElementById('header-root-visual').style.opacity = '1';
    };
  </script>
</div>
